#include<bits/stdc++.h>
using namespace std;
const int mod=5e6+7;
int n,m,k[7],p[7],P[152][7],table[mod],t[mod];
int ans;
int hash123(int x)
{
    int v=x%mod;
    v=(v%mod+mod)%mod;
    while(t[v]&&table[v]!=x)
    {
        v++;
        v%=mod;
    }
    return v;
}
void dfs1(int x,int sum)
{
    if(x>(n/2))
    {
        int tmp=hash123(sum);
        t[tmp]++;
        table[tmp]=sum;
        return;
    }
    for(int i=1;i<=m;i++)
    {
        dfs1(x+1,sum+k[x]*P[i][p[x]]);
    }
}
void dfs2(int x,int sum)
{
    if(x>n)
    {
        int tmp=hash123(sum);
        ans+=t[tmp];
        return;
    }
    for(int i=1;i<=m;i++)
    {
        dfs2(x+1,sum-k[x]*P[i][p[x]]);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        for(int j=0;j<=4;j++)
        {
            if(j==0)
            {
                P[i][j]=1;
            }
            else
            {
                P[i][j]=P[i][j-1]*i;
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&k[i],&p[i]);
    }
    dfs1(1,0);
    dfs2((n/2)+1,0);
    printf("%d",ans);
    return 0;
}
